import React from 'react';

const PanelEditorEmpresas = () => {
  const rubros = [
    'Comercio',
    'Tecnología',
    'Turismo',
    'Educación',
    'Salud',
    'Gastronomía',
    'Industria',
    'Artesanía',
    'Medios',
    'Construcción'
  ];

  return (
    <div className="min-h-screen w-full bg-[#f2f0df] p-6 flex flex-col items-center">
      <h1 className="text-3xl text-[#9fa56c] font-bold font-mono tracking-wide mb-8">Panel de edición</h1>

      <div className="bg-[#202020] rounded-lg shadow-lg w-full max-w-6xl flex flex-col items-center py-8 px-4">
        {/* Fila superior con "rubros" */}
        <div className="text-white text-xl font-semibold mb-4 self-start px-4">rubro</div>

        {/* Rectángulo central negro que se ajusta al contenido */}
        <div className="bg-black p-6 rounded-xl w-auto max-w-full overflow-x-auto">
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-6">
            {/* Título */}
            <div className="col-span-full text-center text-white font-bold text-lg">nombre</div>

            {/* Inputs */}
            {rubros.map((rubro, index) => (
              <input
                key={index}
                type="text"
                value={rubro}
                disabled
                className="bg-white text-black rounded-md px-4 py-2 w-full"
              />
            ))}
          </div>
        </div>

        {/* Botón al fondo */}
        <div className="mt-6">
          <button className="bg-[#9fa56c] text-white px-4 py-2 rounded-full text-sm font-semibold hover:bg-[#8a944e] transition">
            ➕ Añadir rubro
          </button>
        </div>
      </div>
    </div>
  );
};

export default PanelEditorEmpresas;
